1	// Long-running session wrapper around @anthropic-ai/claude-agent-sdk's query().
2	//
3	// All turns share one Query so conversation history persists. Submitting a
4	// turn pushes a user message into a queue that the SDK consumes as
5	// AsyncIterable<SDKUserMessage>; consuming the Query's messages yields raw
6	// SDK objects that this class translates into CoreAgentEvents (plus any
7	// experiment-specific events emitted by registered customToolHandlers).
8	//
9	// Generic over the extra-event type `E` so experiments can extend the event
10	// vocabulary without modifying core. e.g. pair/ uses `Session<OptionsEvent>`.
11	
12	import {
13	  query,
14	  type McpServerConfig,
15	  type SDKUserMessage,
16	} from '@anthropic-ai/claude-agent-sdk';
17	import {
18	  type CoreAgentEvent,
19	  type CustomToolHandler,
20	  type ToolUseBlock,
21	} from './types';
22	
23	
24	// Internal SDK tools that shouldn't appear in the user-facing transcript.
25	// The Node SDK fires `ToolSearch` to resolve deferred MCP tools — pure
26	// plumbing, not real activity.
27	const HIDDEN_TOOL_NAMES = new Set(['ToolSearch']);
28	
29	
30	// Some tool errors come back wrapped in `<tool_use_error>...</tool_use_error>`
31	// (e.g. Write's "File has not been read yet"), others come as plain prose
32	// (e.g. Read's "File does not exist."). Strip the wrapper so the rendered
33	// error line is consistent.
34	function stripToolUseErrorWrapper(text: string): string {
35	  const m = text.match(/^<tool_use_error>([\s\S]*)<\/tool_use_error>\s*$/);
36	  return m ? m[1]!.trim() : text;
37	}
38	
