40	/** Async queue with a `push` method that satisfies AsyncIterable<SDKUserMessage>. */
41	class UserMessageQueue implements AsyncIterable<SDKUserMessage> {
42	  private buffered: SDKUserMessage[] = [];
43	  private waiting: ((m: SDKUserMessage) => void)[] = [];
44	  private closed = false;
45	
46	  push(msg: SDKUserMessage): void {
47	    if (this.closed) return;
48	    const w = this.waiting.shift();
49	    if (w) w(msg);
50	    else this.buffered.push(msg);
51	  }
52	
53	  close(): void {
54	    this.closed = true;
55	    for (const w of this.waiting) w(null as unknown as SDKUserMessage);
56	    this.waiting = [];
57	  }
58	
59	  async *[Symbol.asyncIterator](): AsyncIterator<SDKUserMessage> {
60	    while (!this.closed) {
61	      if (this.buffered.length > 0) {
62	        yield this.buffered.shift()!;
63	        continue;
64	      }
65	      const msg = await new Promise<SDKUserMessage>((resolve) => {
66	        this.waiting.push(resolve);
67	      });
68	      if (this.closed) break;
69	      yield msg;
70	    }
71	  }
72	}
