75	export type SessionOptions<E> = {
76	  systemPrompt: string;
77	  mcpServers?: Record<string, McpServerConfig>;
78	  allowedTools?: string[];
79	  disallowedTools?: string[];
80	  /** Working directory the SDK uses for tool calls (defaults to process.cwd()). */
81	  cwd?: string;
82	  /** Override the model id (defaults to whatever the SDK chooses). */
83	  model?: string;
84	  /**
85	   * Map of tool name (full SDK name like `mcp__server__tool_name`) → handler.
86	   * When the assistant calls a tool whose name is a key here, the handler
87	   * gets the tool_use block and decides what (if anything) to emit. Stream
88	   * events for these tools' content blocks are also suppressed (no
89	   * tool_use_start), and their tool_results are swallowed.
90	   */
91	  customToolHandlers?: Record<string, CustomToolHandler<E>>;
92	};
93	
94	
95	export class Session<E = never> {
96	  private queue = new UserMessageQueue();
97	  private listener: ((ev: CoreAgentEvent | E) => void) | null = null;
98	  private consumePromise: Promise<void> | null = null;
99	  private isAborted = false;
100	
101	  // Tool ids whose tool_result we should suppress (because a custom handler
102	  // is owning the rendering for that tool).
103	  private claimedToolIds = new Set<string>();
104	  // Stream-event indices for tool_use blocks we're not surfacing as
105	  // tool_use_start (so their content_block_delta / content_block_stop also
106	  // get filtered).
107	  private suppressedIndices = new Set<number>();
108	  // Tool ids whose name we've recorded — used to populate the `name` field
109	  // on tool_result events.
110	  private toolNames = new Map<string, string>();
111	  // Ids of tools registered as hidden (ToolSearch + any custom-handled).
112	  private hiddenToolIds = new Set<string>();
113	
114	  private turnStartedAt = Date.now();
115	
116	  constructor(private opts: SessionOptions<E>) {}
117	
118	  /** Begin consuming the long-running Query. Call once at app start. */
119	  start(): void {
120	    if (this.consumePromise) return;
121	    this.isAborted = false;
122	    const q = query({
123	      prompt: this.queue,
124	      options: {
125	        mcpServers: this.opts.mcpServers ?? {},
126	        systemPrompt: this.opts.systemPrompt,
127	        permissionMode: 'bypassPermissions',
128	        allowedTools: this.opts.allowedTools ?? ['Read', 'Glob', 'Grep', 'Edit', 'Write', 'Bash'],
129	        disallowedTools: this.opts.disallowedTools ?? [],
130	        includePartialMessages: true,
131	        ...(this.opts.cwd ? { cwd: this.opts.cwd } : {}),
132	        ...(this.opts.model ? { model: this.opts.model } : {}),
133	      },
134	    });
135	
136	    this.consumePromise = (async () => {
137	      try {
138	        for await (const msg of q) {
139	          if (this.isAborted) break;
140	          this.translate(msg);
141	        }
142	      } catch (e) {
143	        const err = e as Error;
144	        this.emit({ kind: 'error', message: `${err.name}: ${err.message}` } as CoreAgentEvent);
145	      }
146	    })();
147	  }
148	
149	  /** Subscribe to events. Only one listener supported. */
150	  onEvent(handler: (ev: CoreAgentEvent | E) => void): void {
151	    this.listener = handler;
152	  }
153	
154	  /** Send a user prompt; events flow back via the listener. */
155	  send(text: string): void {
156	    this.turnStartedAt = Date.now();
157	    this.isAborted = false;
158	    this.suppressedIndices.clear();
159	    this.queue.push({
160	      type: 'user',
161	      message: { role: 'user', content: text },
162	      parent_tool_use_id: null,
163	    });
164	  }
165	
166	  close(): void {
167	    this.queue.close();
168	  }
169	
170	  /** Cancel the current turn: stop processing events and emit a cancellation message. */
171	  abort(): void {
172	    this.isAborted = true;
173	    this.emit({ kind: 'result', durationMs: Date.now() - this.turnStartedAt, totalCostUsd: 0, numTurns: 0 } as CoreAgentEvent);
174	  }
175	
176	  private emit(ev: CoreAgentEvent | E): void {
177	    this.listener?.(ev);
178	  }
179	
180	  private isCustomTool(name: string): boolean {
181	    return this.opts.customToolHandlers
182	      ? Object.prototype.hasOwnProperty.call(this.opts.customToolHandlers, name)
183	      : false;
184	  }
185	
186	  /**
187	   * Map a single raw SDK message to high-level event(s) via the listener.
188	   * Public so tests can drive translation with synthetic SDK messages —
189	   * runtime callers should not invoke this directly.
190	   */
191	  translate(msg: unknown): void {
192	    const m = msg as { type?: string };
193	    const type = m.type;
194	
195	    if (type === 'stream_event') {
196	      const ev = (msg as {
197	        event: {
198	          type: string;
199	          index?: number;
200	          content_block?: { type: string; name?: string; id?: string };
201	          delta?: { type: string; text?: string };
202	        };
203	      }).event;
204	      const et = ev.type;
205	
206	      if (et === 'message_start') {
207	        this.suppressedIndices.clear();
208	        return;
209	      }
210	      if (et === 'content_block_start') {
211	        const cb = ev.content_block!;
212	        const idx = ev.index;
213	        if (cb.type === 'tool_use') {
214	          const toolName = cb.name ?? '';
215	          this.toolNames.set(cb.id ?? '', toolName);
216	          if (HIDDEN_TOOL_NAMES.has(toolName) || this.isCustomTool(toolName)) {
217	            this.hiddenToolIds.add(cb.id ?? '');
218	            if (idx !== undefined) this.suppressedIndices.add(idx);
219	            return;
220	          }
221	          this.emit({
222	            kind: 'tool_use_start',
223	            id: cb.id ?? '',
224	            name: toolName,
225	            input: {},
226	          });
227	          return;
228	        }
229	        if (cb.type === 'text') return;
230	        return;
231	      }
232	      if (et === 'content_block_delta') {
233	        if (ev.index !== undefined && this.suppressedIndices.has(ev.index)) return;
234	        const d = ev.delta!;
235	        if (d.type === 'text_delta') {
236	          this.emit({ kind: 'text_delta', text: d.text ?? '' });
237	          return;
238	        }
239	      }
240	      if (et === 'content_block_stop') {
241	        if (ev.index !== undefined && this.suppressedIndices.has(ev.index)) return;
242	        this.emit({ kind: 'text_block_done' });
243	      }
244	      return;
245	    }
246	
247	    if (type === 'assistant') {
248	      const am = (msg as {
249	        message: { content: Array<{ type: string; id?: string; name?: string; input?: unknown }> };
250	      }).message;
251	      for (const block of am.content) {
252	        if (block.type !== 'tool_use') continue;
253	        const toolName = block.name ?? '';
254	        const toolId = block.id ?? '';
255	        this.toolNames.set(toolId, toolName);
256	
257	        const customHandler = this.opts.customToolHandlers?.[toolName];
258	        if (customHandler) {
259	          // Always claim the id so the SDK's tool_result (success-stub or
260	          // validation error) is suppressed — regardless of whether the
261	          // handler emits an event.
262	          this.claimedToolIds.add(toolId);
263	          const result = customHandler(block as ToolUseBlock);
264	          if (result !== null && result !== undefined) {
265	            this.emit(result);
266	          }
267	          continue;
268	        }
269	        if (HIDDEN_TOOL_NAMES.has(toolName)) {
270	          this.hiddenToolIds.add(toolId);
271	          continue;
272	        }
273	        this.emit({
274	          kind: 'tool_use_done',
275	          id: toolId,
276	          input: block.input ?? {},
277	        });
278	      }
279	      return;
280	    }
281	
282	    if (type === 'user') {
283	      const um = (msg as {
284	        message: { content: Array<{ type: string; tool_use_id?: string; content?: unknown; is_error?: boolean }> };
285	      }).message;
286	      if (!Array.isArray(um.content)) return;
287	      for (const block of um.content) {
288	        if (block.type !== 'tool_result') continue;
289	        const tuId = block.tool_use_id ?? '';
290	        if (this.claimedToolIds.has(tuId)) continue;
291	        if (this.hiddenToolIds.has(tuId)) continue;
292	        let text = '';
293	        if (typeof block.content === 'string') text = block.content;
294	        else if (Array.isArray(block.content)) {
295	          text = (block.content as Array<{ text?: string }>)
296	            .map((c) => c.text ?? '')
297	            .join('');
298	        }
299	        this.emit({
300	          kind: 'tool_result',
301	          toolUseId: tuId,
302	          name: this.toolNames.get(tuId) ?? 'Tool',
303	          text: stripToolUseErrorWrapper(text),
304	          isError: Boolean(block.is_error),
305	        });
306	      }
307	      return;
308	    }
309	
310	    if (type === 'result') {
311	      const r = msg as {
312	        duration_ms?: number;
313	        total_cost_usd?: number;
314	        num_turns?: number;
315	      };
316	      this.emit({
317	        kind: 'result',
318	        durationMs: r.duration_ms ?? Date.now() - this.turnStartedAt,
319	        totalCostUsd: r.total_cost_usd ?? 0,
320	        numTurns: r.num_turns ?? 0,
321	      });
322	      return;
323	    }
324	  }
325	}
