1	// Generic chat shell. Renders core entry kinds itself; experiments inject a
2	// `renderExtra` callback for any additional kinds (e.g. pair/'s `options`).
3	//
4	// Layout: <Static> for committed past entries (Ink writes them once, never
5	// re-renders, so layout can't corrupt while streaming), live region below
6	// for the currently-streaming assistant block / running tool pill, input
7	// row pinned at the bottom with thin grey rule lines above and below.
8	
9	import React, { useCallback, useEffect, useRef, useState, type ReactNode } from 'react';
10	import { Box, Static, Text, useInput } from 'ink';
11	import { Spinner } from '@inkjs/ui';
12	import { ChatInput } from './components/Input.js';
13	import { type Session } from './Session.js';
14	import { type CoreAgentEvent } from './types.js';
15	import {
16	  AssistantBlock,
17	  ErrorLine,
18	  StepFooter,
19	  ToolPillRunning,
20	  ToolResult,
21	  UserLine,
22	} from './components/Entries.js';
23	
24	
25	// "Committed" entries — already past, won't change. Subset of AgentEvent
26	// kinds plus the entry envelope.
27	type CoreFrozenEntry =
28	  | { kind: 'user'; text: string }
29	  | { kind: 'assistant'; text: string }
30	  | {
31	      kind: 'tool';
32	      name: string;
33	      input: unknown;
34	      result: { text: string; isError: boolean } | null;
35	    }
36	  | { kind: 'footer'; elapsedSec: number }
37	  | { kind: 'error'; message: string };
38	
39	// "Live" entries — currently streaming.
40	type CoreLiveEntry =
41	  | { kind: 'assistant'; text: string }
42	  | { kind: 'tool'; id: string; name: string; input: unknown }
43	  | null;
44	
45	/**
46	 * Optional extension point for experiments: when the session emits an event
47	 * with a kind core doesn't handle, the App passes it to `renderExtraEvent`,
48	 * which can:
49	 *   - Return an `ExtraEntry` to freeze in the transcript.
50	 *   - Return `null` to ignore the event.
51	 *   - Return a `{ render: ReactNode }` directly to render once-only (rare).
52	 *
53	 * The extra entries are then rendered via `renderExtra(entry)`.
54	 */
55	export type ExtraExtension<E, X> = {
56	  reduce: (event: E) => X | null;
57	  render: (entry: X, index: number) => ReactNode;
58	};
59	
60	
61	const LOADING_WORDS = [
62	  'Thinking', 'Pondering', 'Cogitating', 'Musing', 'Ruminating',
63	  'Brewing', 'Brainstorming', 'Mulling', 'Deliberating', 'Reflecting',
64	  'Considering', 'Distilling', 'Crystallizing', 'Reasoning', 'Plotting',
65	  'Galloping', 'Simmering', 'Percolating', 'Noodling',
66	];
67	
68	function pickLoadingWord(): string {
69	  return LOADING_WORDS[Math.floor(Math.random() * LOADING_WORDS.length)]!;
70	}
71	
72	
73	export function App<E = never, X = never>({
74	  session,
75	  extra,
76	}: {
77	  session: Session<E>;
78	  extra?: ExtraExtension<E, X>;
79	}) {
80	  const [frozen, setFrozen] = useState<Array<CoreFrozenEntry | { kind: '__extra__'; entry: X }>>([]);
81	  const [live, setLive] = useState<CoreLiveEntry>(null);
82	  const [busy, setBusy] = useState(false);
83	  const [loadingWord, setLoadingWord] = useState(() => pickLoadingWord());
84	  const [inputKey, setInputKey] = useState(0);
85	  const [history, setHistory] = useState<string[]>([]);
86	  const turnStartRef = useRef<number>(0);
87	  // Mirror of `live` we can read SYNCHRONOUSLY inside event handlers. React
88	  // would otherwise queue setLive callbacks behind direct setFrozen calls,
89	  // producing wrong-order commits (we hit a real bug where the step footer
90	  // was queued before the assistant text it should follow). All `freeze`
91	  // calls now run in raw call order; `setLive` and `liveRef.current` are
92	  // kept in lockstep via a wrapper.
93	  const liveRef = useRef<CoreLiveEntry>(null);
94	
95	  const updateLive = useCallback((next: CoreLiveEntry) => {
96	    liveRef.current = next;
97	    setLive(next);
98	  }, []);
99	
100	  const freeze = useCallback(
101	    (entry: CoreFrozenEntry | { kind: '__extra__'; entry: X }) => {
102	      setFrozen((prev) => [...prev, entry]);
103	    },
104	    [],
105	  );
106	
107	  const handleEvent = useCallback(
108	    (ev: CoreAgentEvent | E) => {
109	      const e = ev as { kind: string };
110	      if (e.kind === 'text_delta') {
111	        const t = (ev as { text: string }).text;
112	        const cur = liveRef.current;
113	        if (cur && cur.kind === 'assistant') {
114	          updateLive({ ...cur, text: cur.text + t });
115	        } else {
116	          updateLive({ kind: 'assistant', text: t });
117	        }
118	        return;
119	      }
120	      if (e.kind === 'text_block_done') {
121	        const cur = liveRef.current;
122	        if (cur && cur.kind === 'assistant') {
123	          updateLive(null);
124	          freeze({ kind: 'assistant', text: cur.text });
125	        }
126	        return;
127	      }
128	      if (e.kind === 'tool_use_start') {
129	        const t = ev as { id: string; name: string; input: unknown };
130	        const cur = liveRef.current;
131	        if (cur && cur.kind === 'assistant') {
132	          freeze({ kind: 'assistant', text: cur.text });
133	        }
134	        updateLive({ kind: 'tool', id: t.id, name: t.name, input: t.input });
135	        return;
136	      }
137	      if (e.kind === 'tool_use_done') {
138	        const t = ev as { id: string; input: unknown };
139	        const cur = liveRef.current;
140	        if (cur && cur.kind === 'tool' && cur.id === t.id) {
141	          updateLive({ ...cur, input: t.input });
142	        }
143	        return;
144	      }
145	      if (e.kind === 'tool_result') {
146	        const t = ev as { toolUseId: string; name: string; text: string; isError: boolean };
147	        const cur = liveRef.current;
148	        if (cur && cur.kind === 'tool' && cur.id === t.toolUseId) {
149	          updateLive(null);
150	          freeze({
151	            kind: 'tool',
152	            name: cur.name,
153	            input: cur.input,
154	            result: { text: t.text, isError: t.isError },
155	          });
156	        } else {
157	          freeze({
158	            kind: 'tool',
159	            name: t.name,
160	            input: {},
161	            result: { text: t.text, isError: t.isError },
162	          });
163	        }
164	        return;
165	      }
166	      if (e.kind === 'result') {
167	        const cur = liveRef.current;
168	        if (cur && cur.kind === 'assistant') {
169	          updateLive(null);
170	          freeze({ kind: 'assistant', text: cur.text });
171	        }
172	        const elapsed = (Date.now() - turnStartRef.current) / 1000;
173	        freeze({ kind: 'footer', elapsedSec: elapsed });
174	        setBusy(false);
175	        return;
176	      }
177	      if (e.kind === 'error') {
178	        const t = ev as { message: string };
179	        freeze({ kind: 'error', message: t.message });
180	        setBusy(false);
181	        return;
182	      }
183	      // Unknown kind — try the experiment extension.
184	      if (extra) {
185	        const x = extra.reduce(ev as E);
186	        if (x !== null && x !== undefined) {
187	          const cur = liveRef.current;
188	          if (cur && cur.kind === 'assistant') {
189	            updateLive(null);
190	            freeze({ kind: 'assistant', text: cur.text });
191	          }
192	          freeze({ kind: '__extra__', entry: x });
193	        }
194	      }
195	    },
196	    [extra, freeze, updateLive],
197	  );
198	
199	  // Wire session.
200	  useEffect(() => {
201	    session.onEvent(handleEvent);
202	    session.start();
203	    return () => session.close();
204	  }, [session, handleEvent]);
205	
206	  // Rotate loader word every ~2.2s while busy.
207	  useEffect(() => {
208	    if (!busy) return;
209	    const t = setInterval(() => setLoadingWord(pickLoadingWord()), 2200);
210	    return () => clearInterval(t);
211	  }, [busy]);
212	
213	  const onSubmit = useCallback(
214	    (text: string) => {
215	      const trimmed = text.trim();
216	      if (!trimmed || busy) return;
217	      setInputKey((k) => k + 1);
218	      setBusy(true);
219	      setLoadingWord(pickLoadingWord());
220	      setHistory((h) => (h[h.length - 1] === trimmed ? h : [...h, trimmed]));
221	      freeze({ kind: 'user', text: trimmed });
222	      turnStartRef.current = Date.now();
223	      session.send(trimmed);
224	    },
225	    [busy, freeze, session],
226	  );
227	
228	  // Interrupt handler: Escape cancels a running turn.
229	  useInput(
230	    (input, key) => {
231	      if (key.escape && busy) {
232	        session.abort();
233	        setBusy(false);
234	      }
235	    },
236	    { isActive: busy },
237	  );
238	
239	  // Show the spinner whenever the model is doing something but there's
240	  // nothing visible streaming yet — i.e. before the first event of a turn
241	  // AND in the gaps between tool_result and the next assistant block (the
242	  // model is "thinking up" a follow-up).
243	  const showLoader = busy && live === null;
244	
245	  return (
246	    <>
247	      <Static items={frozen.map((entry, i) => ({ entry, i }))}>
248	        {({ entry, i }) => {
249	          if (entry.kind === '__extra__') {
250	            if (extra) return <React.Fragment key={i}>{extra.render(entry.entry, i)}</React.Fragment>;
251	            return null;
252	          }
253	          if (entry.kind === 'user') return <UserLine key={i} text={entry.text} />;
254	          if (entry.kind === 'assistant') return <AssistantBlock key={i} text={entry.text} />;
255	          if (entry.kind === 'tool') {
256	            if (entry.result) {
257	              return (
258	                <ToolResult
259	                  key={i}
260	                  name={entry.name}
261	                  input={entry.input}
262	                  text={entry.result.text}
263	                  isError={entry.result.isError}
264	                />
265	              );
266	            }
267	            return <ToolPillRunning key={i} name={entry.name} input={entry.input} />;
268	          }
269	          if (entry.kind === 'footer') return <StepFooter key={i} elapsedSec={entry.elapsedSec} />;
270	          if (entry.kind === 'error') return <ErrorLine key={i} message={entry.message} />;
271	          return null;
272	        }}
273	      </Static>
274	
275	      {live && live.kind === 'assistant' ? <AssistantBlock text={live.text} /> : null}
276	      {live && live.kind === 'tool' ? <ToolPillRunning name={live.name} input={live.input} /> : null}
277	
